SELECT count(*) FROM role_type, cast_info, title, movie_info, name, aka_name, info_type WHERE cast_info.role_id = role_type.id AND cast_info.movie_id = title.id AND movie_info.movie_id = title.id AND cast_info.person_id = name.id AND aka_name.person_id = name.id AND movie_info.info_type_id = info_type.id;